isDisabled:
{{
(() => {

  const selectedDept = appsmith.store.selectedDepartment_Questions?.trim().toLowerCase();
  const questions = List_Questions.listData || [];
  const answers = appsmith.store.answers_Questions || {};
  const signOffs = GetDepartmentSignOff.data || [];

  // 🔥 FIXED TYPE CHECK
  const isApprover = Number(appsmith.store.userContext?.isApprover) === 1;

  if (!isApprover) return true;

  if (!selectedDept || !questions.length) return true;

  const deptQuestions = questions.filter(q =>
    q.Department?.trim().toLowerCase() === selectedDept
  );

  if (!deptQuestions.length) return true;

  const incomplete = deptQuestions.some(q => {

    const ans = answers[q.id];

    if (!ans || ans.YesNo === undefined) return true;

    if (Number(ans.YesNo) === 0) {
      const responsible = ans.ResponsiblePerson?.toString().trim();
      const action = ans.Action?.toString().trim();
      const due = ans.DueDate?.toString().trim();
      return (!responsible || !action || !due);
    }

    return false;

  });

  const isComplete = !incomplete;

  const deptSign = signOffs.find(s =>
    s.Department?.trim().toLowerCase() === selectedDept
  );

  const isSigned = Number(deptSign?.SignedOff) === 1;

  return !isComplete || isSigned;

})()
}}

tooltip:
{{
!appsmith.store.userContext?.isApprover
  ? "You do not have approval rights"
  : "Approve department"
}}
